raw_output:
{
  "experiment_plan": {
    "what_to_compare": "米国の8年生・10年生・12年生について、1991-2011年と2012-2016年の心理的well-being水準を比較する。同時に、年次レベルでスクリーン活動（電子コミュニケーション、ソーシャルメディア、インターネット、ゲーム、テキスト）と非スクリーン活動（対面交流、スポーツ、宿題、宗教活動）、および経済指標（失業率）との関連を比較する。さらに、電子コミュニケーションとwell-being、失業率とwell-beingの時系列先行関係を比較する。",
    "what_to_measure": "主要アウトカムは自尊感情、生活満足度、領域満足度、幸福感の複合指標。説明変数は各活動頻度の自己報告、週あたりスクリーンタイム、年次失業率。補助的に、年次トレンド、個人レベル相関、集計レベル相関、Granger因果の方向性を測定する。",
    "procedure": "Monitoring the Futureの反復横断データを用い、各年の新規コホートを対象に年齢層別・年別のwell-beingを推定する。次に、活動頻度とwell-beingの横断相関を推定し、スクリーン活動と非スクリーン活動の効果量を比較する。続いて、年次集計データで電子コミュニケーション、失業率、well-beingの時系列モデルを推定し、Granger因果とラグ付き回帰で方向性を検証する。最後に、スクリーン活動と経済指標を同時投入したモデルで独立寄与を評価し、各仮説の判定規則に従ってaccept/reject/holdを決める。",
    "identification_assumptions": [
      {
        "id": "IA1",
        "description": "年次比較において、2012年を境とする制度・測定・サンプル構成の大きな断絶がなく、観測された変化は実際のwell-being変化を反映する。",
        "if_violated": "2012年前後の変化が調査設計や回答傾向の変更によるものであれば、2012年以降の低下を因果的変化として解釈できない。"
      },
      {
        "id": "IA2",
        "description": "自己報告のスクリーン活動頻度とwell-being指標は、少なくとも年次比較と相関分析において系統的な測定誤差が時間とともに大きく変化しない。",
        "if_violated": "報告バイアスが年ごとに変化すると、スクリーン活動とwell-beingの関連やトレンドが歪む。"
      },
      {
        "id": "IA3",
        "description": "Granger分析に必要な条件として、モデルに含めたラグ構造が主要な動学を十分に捉え、未観測の強い共通ショックが残らない。",
        "if_violated": "未観測ショックが残ると、先行関係を因果方向として解釈できない。"
      },
      {
        "id": "IA4",
        "description": "失業率は青少年well-beingに対する経済環境の妥当な代理変数であり、少なくとも年次レベルでは主要な経済ストレスを近似する。",
        "if_violated": "失業率が経済的要因を十分に表さない場合、H2の判定は弱くなる。"
      },
      {
        "id": "IA5",
        "description": "個人レベルの活動頻度とwell-beingの相関は、少なくとも主要な観測交絡を統制した後に比較可能である。",
        "if_violated": "交絡が強いと、スクリーン活動と非スクリーン活動の比較が因果的含意を持たない。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
        "accept_if": "2012年以降のwell-being低下が明確で、スクリーン活動の増加が同時期に先行または同調し、電子コミュニケーション/ソーシャルメディアがwell-beingに一貫して負の関連を示し、非スクリーン活動よりもスクリーン活動の負の関連が大きい。さらに、年次Granger分析でスクリーン活動→well-beingがwell-being→スクリーン活動より強い。",
        "reject_if": "2012年以降にwell-being低下が見られない、またはスクリーン活動の増加がwell-being低下に先行しない、あるいは電子コミュニケーションがwell-beingを予測しない、もしくは非スクリーン活動の方が同等以上に強い負の関連を示す。",
        "hold_if": "well-being低下はあるが、スクリーン活動との時系列対応や方向性が不明確で、負の関連が弱いか他要因と区別できない。"
      },
      {
        "id": "H2",
        "accept_if": "失業率などの経済指標がwell-being低下に先行して関連し、スクリーン活動を統制すると経済指標の説明力が残り、Granger分析で経済指標→well-beingが優勢で、スクリーン活動→well-beingが弱い。",
        "reject_if": "失業率が悪化していない、または経済指標がwell-beingを予測せず、スクリーン活動を統制してもwell-being低下が説明されない、あるいはスクリーン活動の方が強い先行予測を示す。",
        "hold_if": "経済指標とwell-beingの関連はあるが、スクリーン活動との比較で優勢性が決められず、方向性も不安定である。"
      },
      {
        "id": "H3",
        "accept_if": "スクリーン活動と経済指標の双方が同時投入モデルで独立に有意かつ実質的な係数を持ち、どちらか一方を除いても他方の効果が消失しない。年次トレンドでも両者が部分的に異なる変動を示しつつwell-being低下が継続する。",
        "reject_if": "スクリーン活動または経済指標のどちらか一方だけでwell-being低下が十分に説明され、もう一方の独立寄与が統計的または実質的に消失する。",
        "hold_if": "両者とも関連はあるが、同時投入後の独立寄与が弱く、複合要因モデルとしての優位性が明確でない。"
      },
      {
        "id": "H4",
        "accept_if": "well-being低下→後続のスクリーン活動増加の方向が、スクリーン活動→well-beingより強く、または第三要因を統制するとスクリーン活動とwell-beingの関連が大きく減衰する。さらに、高スクリーン活動群がもともと低well-being群に偏っている。",
        "reject_if": "スクリーン活動の増加がwell-being低下に先行し、逆方向の予測より強い、または第三要因を統制してもスクリーン活動→well-beingの関係が残る。",
        "hold_if": "逆因果や共通原因を示唆する兆候はあるが、方向性の優劣や第三要因の影響が十分に識別できない。"
      }
    ],
    "analysis_forks": [
      "年次トレンド分析: 1991-2011年と2012-2016年の平均well-being差を推定する分岐",
      "個人レベル相関分析: スクリーン活動と非スクリーン活動のどちらがwell-beingと強く関連するかを比較する分岐",
      "経済要因モデル: 失業率を含むモデルと含まないモデルを比較する分岐",
      "同時投入モデル: スクリーン活動と経済指標を同時に入れて独立寄与を検証する分岐",
      "Granger因果分析: スクリーン活動→well-being、well-being→スクリーン活動、経済指標→well-beingの方向を比較する分岐",
      "層別分析: 学年別（8年生・10年生・12年生）および性別で効果の頑健性を確認する分岐",
      "感度分析: ラグ長、アウトカム定義、活動カテゴリの統合方法を変えて結論の安定性を確認する分岐"
    ]
  }
}
